import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import "../styles/transfe.css"; // 👈 este debe coincidir EXACTO

const Transferencias = () => {
  const navigate = useNavigate();

  const [destino, setDestino] = useState("");
  const [monto, setMonto] = useState("");
  const [tipoCuenta, setTipoCuenta] = useState("");
  const [saldo, setSaldo] = useState(0);
  const [mensaje, setMensaje] = useState("");

  const documento = localStorage.getItem("documento");

  useEffect(() => {
    if (!tipoCuenta || !documento) return;

    const obtenerSaldo = async () => {
      try {
        const res = await fetch(
          `http://127.0.0.1:8000/saldo/${documento}/${tipoCuenta}`
        );
        const data = await res.json();

        if (res.ok) setSaldo(data.saldo);
        else setSaldo(0);

      } catch (error) {
        console.error(error);
        setSaldo(0);
      }
    };

    obtenerSaldo();
  }, [tipoCuenta, documento]);

  const handleTransferencia = async (e) => {
    e.preventDefault();

    if (!tipoCuenta) return setMensaje("Selecciona tipo de cuenta");
    if (!destino.trim()) return setMensaje("Ingresa destino");
    if (!monto || monto <= 0) return setMensaje("Monto inválido");
    if (monto > saldo) return setMensaje("Saldo insuficiente");

    try {
      const res = await fetch("http://127.0.0.1:8000/transferir", {
        method: "POST",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify({
          origen: documento,
          destino: destino.trim(),
          monto: parseFloat(monto),
          tipo_cuenta: tipoCuenta
        })
      });

      const data = await res.json();

      if (res.ok) {
        setMensaje("Transferencia exitosa");
        setDestino("");
        setMonto("");
        setTipoCuenta("");
      } else {
        setMensaje(data.detail);
      }

    } catch {
      setMensaje("Error del servidor");
    }
  };

  return (
    <div className="transferencias-container">
      <div className="transferencias-box">
        <h2>Transferencias</h2>

        <form onSubmit={handleTransferencia}>

          <label>Tipo de cuenta</label>
          <select
            value={tipoCuenta}
            onChange={(e) => setTipoCuenta(e.target.value)}
          >
            <option value="">Seleccione</option>
            <option value="ahorros">Ahorros</option>
            <option value="corriente">Corriente</option>
          </select>

          {tipoCuenta && (
            <p className="saldo">Saldo: ${saldo}</p>
          )}

          <label>Destino</label>
          <input
            value={destino}
            onChange={(e) => setDestino(e.target.value)}
          />

          <label>Monto</label>
          <input
            type="number"
            value={monto}
            onChange={(e) => setMonto(e.target.value)}
          />

          <button type="submit">Enviar</button>
        </form>

        {mensaje && <p>{mensaje}</p>}

        <button onClick={() => navigate("/cuenta")}>
          Volver
        </button>
      </div>
    </div>
  );
};

export default Transferencias;
